# app.py (Flask part)
from flask import Flask, request, jsonify

app = Flask(__name__)

@app.route('/annotate', methods=['POST'])
def annotate():
    data = request.get_json()
    image_id = data['image_id']
    label = data['label']
    Annotation.objects.create(image_id=image_id, label=label)
    return jsonify({'status': 'success'})

if __name__ == '__main__':
    app.run()

# models.py (Django part)
from django.db import models

class Image(models.Model):
    id = models.AutoField(primary_key=True)
    # image fields...

class Annotation(models.Model):
    id = models.AutoField(primary_key=True)
    image = models.ForeignKey(Image, on_delete=models.CASCADE)
    label = models.CharField(max_length=255)

# train.py (scikit-learn part)
from sklearn.model_selection import train_test_split
from sklearn.datasets import load_dataset
from sklearn.linear_model import LogisticRegression

def get_train_data():
    data = load_dataset('digits')
    annotations = Annotation.objects.all()
    labels = [annotation.label for annotation in annotations]
    X_train, X_test, y_train, y_test = train_test_split(data.data, labels, test_size=0.2)
    return X_train, y_train

def train_model():
    X_train, y_train = get_train_data()
    clf = LogisticRegression()
    clf.fit(X_train, y_train)
    return clf